import subprocess
import urllib.request
import json
import sys

def run_cmd(cmd):
    try:
        return subprocess.check_output(cmd, shell=True, text=True, stderr=subprocess.STDOUT).strip()
    except subprocess.CalledProcessError as e:
        return f"ERR: {e.output.strip()}"
    except Exception as e:
        return f"ERR: {str(e)}"

def pull_notion():
    try:
        req = urllib.request.Request(
            "https://api.notion.so/v1/databases/sprint/query", 
            data=json.dumps({}).encode('utf-8'), 
            headers={"Content-Type": "application/json"}
        )
        with urllib.request.urlopen(req, timeout=5) as response:
            data = json.loads(response.read().decode('utf-8'))
            # Extremely compressed notion output
            res = []
            for item in data.get('results', []):
                props = item.get('properties', {})
                name = props.get('Name', {}).get('title', [{}])[0].get('plain_text', 'N/A')
                status = props.get('Status', {}).get('status', {}).get('name', 'N/A')
                res.append(f"{name}:{status}")
            return " | ".join(res) if res else "No tasks"
    except Exception as e:
        return f"Notion ERR: {str(e)}"

def main():
    print("[DATA FAST PULL]")

    # 1. Emails (Headers only)
    mail = run_cmd("himalaya envelope list --limit 10")
    print(f"MAIL: {mail[:500]}") # Keep it short

    # 2. Calendar
    cal = run_cmd("gcalcli agenda")
    print(f"CAL: {cal[:300]}")

    # 3. Notion
    notion = pull_notion()
    print(f"TASKS: {notion[:300]}")

if __name__ == "__main__":
    main()
